const fs = require("fs");
const path = require("path");

const root = process.cwd();

const LIGHT_LOGO_BASE64 = "";
const DARK_LOGO_BASE64 = "";
const COMPONENT_CODE = "\"use client\";\n\nimport { ImgHTMLAttributes, useEffect, useState } from \"react\";\n\ntype LoadLinkLogoProps = ImgHTMLAttributes<HTMLImageElement> & {\n  containerClassName?: string;\n  showGlow?: boolean;\n};\n\nfunction detectDarkMode() {\n  if (typeof window === \"undefined\") return false;\n\n  const savedTheme = localStorage.getItem(\"loadlink-theme\");\n  if (savedTheme === \"dark\") return true;\n  if (savedTheme === \"light\") return false;\n\n  return Boolean(\n    document.querySelector(\"main.bg-black\") ||\n    document.querySelector(\"header.bg-black\") ||\n    document.querySelector(\".bg-black\") ||\n    document.documentElement.classList.contains(\"dark\") ||\n    document.body.classList.contains(\"dark\")\n  );\n}\n\nexport default function LoadLinkLogo({\n  className = \"h-auto w-[150px] object-contain md:w-[190px]\",\n  containerClassName = \"\",\n  showGlow = true,\n  alt = \"LoadLink\",\n  ...props\n}: LoadLinkLogoProps) {\n  const [darkMode, setDarkMode] = useState(false);\n\n  useEffect(() => {\n    const sync = () => setDarkMode(detectDarkMode());\n\n    sync();\n\n    const observer = new MutationObserver(sync);\n    observer.observe(document.documentElement, { attributes: true, childList: true, subtree: true });\n    if (document.body) observer.observe(document.body, { attributes: true, childList: true, subtree: true });\n\n    const timer = window.setInterval(sync, 200);\n\n    window.addEventListener(\"storage\", sync);\n    window.addEventListener(\"click\", sync);\n    window.addEventListener(\"loadlink-theme-change\", sync);\n\n    return () => {\n      observer.disconnect();\n      window.clearInterval(timer);\n      window.removeEventListener(\"storage\", sync);\n      window.removeEventListener(\"click\", sync);\n      window.removeEventListener(\"loadlink-theme-change\", sync);\n    };\n  }, []);\n\n  return (\n    <span className={`loadlink-logo-wrap relative inline-flex items-center justify-center ${containerClassName}`}>\n      {showGlow ? (\n        <span\n          aria-hidden=\"true\"\n          className=\"pointer-events-none absolute left-1/2 top-1/2 z-0 h-[132%] w-[132%] -translate-x-1/2 -translate-y-1/2 rounded-full blur-2xl\"\n          style={{\n            background:\n              \"radial-gradient(circle, rgba(246,184,0,0.38) 0%, rgba(246,184,0,0.20) 38%, rgba(246,184,0,0) 74%)\",\n          }}\n        />\n      ) : null}\n\n      <img\n        src={darkMode ? \"/images/loadlink-logo-dark.png?v=embedded-final\" : \"/images/loadlink-logo-light.png?v=embedded-final\"}\n        alt={alt}\n        className={`loadlink-logo-img relative z-10 ${className}`}\n        style={{ filter: \"none\" }}\n        {...props}\n      />\n    </span>\n  );\n}\n";

function writeFileSafe(filePath, content) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content);
}

function walk(dir, files = []) {
  if (!fs.existsSync(dir)) return files;

  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    if (entry.name === "node_modules" || entry.name === ".next" || entry.name === ".git") continue;

    const full = path.join(dir, entry.name);

    if (entry.isDirectory()) walk(full, files);
    else if (/\.(tsx|jsx)$/.test(entry.name)) files.push(full);
  }

  return files;
}

function ensureImport(code) {
  const importLine = 'import LoadLinkLogo from "@/components/LoadLinkLogo";';

  if (code.includes(importLine)) return code;

  if (code.startsWith('"use client";')) {
    return code.replace('"use client";', '"use client";\n\n' + importLine);
  }

  if (code.startsWith("'use client';")) {
    return code.replace("'use client';", "'use client';\n\n" + importLine);
  }

  const firstImport = code.match(/^import .+?;\n/m);
  if (firstImport) {
    return code.replace(firstImport[0], firstImport[0] + importLine + "\n");
  }

  return importLine + "\n" + code;
}

function extractClassName(tag) {
  const normal = tag.match(/className=["']([^"']*)["']/);
  if (normal) return normal[1].replace(/\s*loadlink-logo-dark-fix\s*/g, " ").trim();

  const template = tag.match(/className=\{`([^`]*)`\}/);
  if (template) return template[1].replace(/\$\{[^}]*\}/g, "").replace(/\s*loadlink-logo-dark-fix\s*/g, " ").trim();

  return "h-auto w-[150px] object-contain md:w-[190px]";
}

function isLoadlinkLogoTag(tag) {
  const lower = tag.toLowerCase();

  if (!(lower.startsWith("<img") || lower.startsWith("<image"))) return false;

  return (
    lower.includes("loadlink-logo") ||
    lower.includes("loadlink logo") ||
    lower.includes("loadlink") ||
    lower.includes('alt="loadlink"') ||
    lower.includes("alt='loadlink'")
  );
}

function replaceLogoTags(code) {
  let count = 0;

  const next = code.replace(/<(img|Image)\b[\s\S]*?>/g, (tag) => {
    if (!isLoadlinkLogoTag(tag)) return tag;

    count += 1;
    const className = extractClassName(tag) || "h-auto w-[150px] object-contain md:w-[190px]";
    return `<LoadLinkLogo className="${className}" />`;
  });

  return { next, count };
}

// 1) Install real logo files from embedded base64.
writeFileSafe(
  path.join(root, "public", "images", "loadlink-logo-light.png"),
  Buffer.from(LIGHT_LOGO_BASE64, "base64")
);

writeFileSafe(
  path.join(root, "public", "images", "loadlink-logo-dark.png"),
  Buffer.from(DARK_LOGO_BASE64, "base64")
);

// keep old path pointing to correct light logo
writeFileSafe(
  path.join(root, "public", "images", "loadlink-logo.png"),
  Buffer.from(LIGHT_LOGO_BASE64, "base64")
);

// 2) Install component.
writeFileSafe(path.join(root, "components", "LoadLinkLogo.tsx"), COMPONENT_CODE);

// 3) Patch all logo image tags.
const searchRoots = ["app", "components", "src/app", "src/components"]
  .map((folder) => path.join(root, folder))
  .filter((folder) => fs.existsSync(folder));

let patchedTags = 0;
const changedFiles = [
  "public/images/loadlink-logo-light.png",
  "public/images/loadlink-logo-dark.png",
  "public/images/loadlink-logo.png",
  "components/LoadLinkLogo.tsx",
];

for (const dir of searchRoots) {
  for (const file of walk(dir)) {
    if (file.endsWith(path.join("components", "LoadLinkLogo.tsx"))) continue;

    const before = fs.readFileSync(file, "utf8");
    const result = replaceLogoTags(before);

    if (result.count > 0) {
      fs.writeFileSync(file, ensureImport(result.next));
      patchedTags += result.count;
      changedFiles.push(path.relative(root, file));
    }
  }
}

// 4) Remove broken filter CSS and add final safety CSS.
const globalsPath = path.join(root, "app", "globals.css");
if (fs.existsSync(globalsPath)) {
  let css = fs.readFileSync(globalsPath, "utf8");

  css = css.replace(/\/\* LoadLink dark mode logo fix:[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LOADLINK DARK LOGO FINAL FIX[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink dark mode business text safety fix[\s\S]*?\}\n?/g, "");
  css = css.replace(/\/\* LoadLink logo swap uses real light\/dark logo files[\s\S]*?\}\n?/g, "");

  if (!css.includes("LOADLINK EMBEDDED FINAL LOGO SAFETY")) {
    css += `
/* LOADLINK EMBEDDED FINAL LOGO SAFETY */
img.loadlink-logo-img,
main.bg-black img.loadlink-logo-img,
header img.loadlink-logo-img,
.bg-black img.loadlink-logo-img {
  filter: none !important;
}

.loadlink-logo-wrap {
  isolation: isolate;
}
`;
  }

  fs.writeFileSync(globalsPath, css);
  changedFiles.push(path.relative(root, globalsPath));
}

// 5) Force deployment stamp.
const stampPath = path.join(root, "loadlink-embedded-final-logo-fix.txt");
writeFileSafe(
  stampPath,
  `Applied embedded final logo fix at ${new Date().toISOString()}\nPatched logo tags: ${patchedTags}\nChanged files:\n${changedFiles.join("\n")}\n`
);
changedFiles.push(path.relative(root, stampPath));

console.log("EMBEDDED FINAL LOGO FIX APPLIED");
console.log("Patched logo tags:", patchedTags);
console.log("Changed files:");
changedFiles.forEach((file) => console.log("- " + file));

if (patchedTags === 0) {
  console.log("");
  console.log("NOTE: No old <img> logo tags were found. That is okay only if the site was already using components/LoadLinkLogo.tsx.");
  console.log("The logo files and LoadLinkLogo component were still replaced.");
}
